using Avalonia;
using Avalonia.Controls;
using Avalonia.Input;
using Avalonia.Media;

private bool _isPanning;
private Point _panStart;
private Vector _panStartOffset;

private void OnCanvasPointerPressed(object? sender, PointerPressedEventArgs e)
{
    // Si le bouton du milieu de la souris n'est pas enfoncé, ne rien faire
    if (!e.GetCurrentPoint(Root_ScrollViewer).Properties.IsMiddleButtonPressed)
        return;

    _isPanning = true;
    _panStart = e.GetPosition(this);
    _panStartOffset = Root_ScrollViewer.Offset;
    e.Handled = true;
}

private void OnCanvasPanMoved(object? sender, PointerEventArgs e)
{
    // Si le défilement manuel n'est pas actif, ne rien faire
    if (!_isPanning)
        return;

    var current = e.GetPosition(this);
    var offsetX = _panStartOffset.X + (_panStart.X - current.X);
    var offsetY = _panStartOffset.Y + (_panStart.Y - current.Y);

    // Calculer les décalages maximaux autorisés pour éviter le débordement
    var maxX = Math.Max(0, Root_ScrollViewer.Extent.Width - Root_ScrollViewer.Viewport.Width);
    var maxY = Math.Max(0, Root_ScrollViewer.Extent.Height - Root_ScrollViewer.Viewport.Height);

    var layoutChanged = false;

    // Gestion du débordement à gauche
    if (offsetX < 0)
    {
        _workflowViewModel.Layout.NegativeOffset += new Offset(-offsetX, 0);
        offsetX = 0;
        layoutChanged = true;
    }
    // Gestion du débordement à droite
    else if (offsetX > maxX)
    {
        _workflowViewModel.Layout.PositiveOffset += new Offset(offsetX - maxX, 0);
        offsetX = maxX;
        layoutChanged = true;
    }

    // Gestion du débordement en haut
    if (offsetY < 0)
    {
        _workflowViewModel.Layout.NegativeOffset += new Offset(0, -offsetY);
        offsetY = 0;
        layoutChanged = true;
    }
    // Gestion du débordement en bas
    else if (offsetY > maxY)
    {
        _workflowViewModel.Layout.PositiveOffset += new Offset(0, offsetY - maxY);
        offsetY = maxY;
        layoutChanged = true;
    }

    // Si la disposition a changé, appliquer la nouvelle mise en page
    if (layoutChanged)
    {
        ApplyCanvasLayout();
        _panStart = current;
        _panStartOffset = Root_ScrollViewer.Offset;
    }

    // Appliquer le nouveau décalage au contrôle de défilement
    Root_ScrollViewer.Offset = new Vector(offsetX, offsetY);
    e.Handled = true;
}

private void OnCanvasPanReleased(object? sender, PointerReleasedEventArgs e)
{
    // Désactiver le défilement manuel
    _isPanning = false;
}

private void ApplyCanvasLayout()
{
    // Appliquer la transformation de décalage sur le canevas
    CanvasTransform = new TransformGroup
    {
        Children =
        [
            new TranslateTransform(
                _workflowViewModel.Layout.ActualOffset.Horizontal,
                _workflowViewModel.Layout.ActualOffset.Vertical)
        ]
    };
}

