private void SyncSlotLayouts()
{
    // Synchronise les dispositions des emplacements (slots)
    if (DataContext is not ViewModels.NodeViewModel node)
        return;

    SyncSlot(PART_InputSlot, node.InputSlot, node);
    SyncSlot(PART_OutputSlot, node.OutputSlot, node);
}

private void SyncSlot(Control? control, IWorkflowSlotViewModel? slot, IWorkflowNodeViewModel node)
{
    // Synchronise un emplacement (slot) donné avec sa position réelle dans le canevas parent
    if (control is null || slot is null || _parentCanvas is null)
        return;

    if (control.Bounds.Width <= 0 || control.Bounds.Height <= 0)
        return;

    var center = control.TranslatePoint(
        new Point(control.Bounds.Width / 2, control.Bounds.Height / 2),
        _parentCanvas);

    if (center is null)
        return;

    var actualOffset = (node.Parent as ViewModels.TreeViewModel)?.Layout.ActualOffset;

    slot.Anchor = new Anchor(
        center.Value.X - (actualOffset?.Horizontal ?? 0),
        center.Value.Y - (actualOffset?.Vertical ?? 0),
        slot.Anchor.Layer);
}

